const e=JSON.parse('{"key":"v-d5db7a4c","path":"/%E8%AF%81%E5%88%B8%E4%BA%A4%E6%98%93/%E9%81%93%E6%B0%8F%E7%90%86%E8%AE%BA%EF%BC%88%E5%9C%B0%E9%9C%87%E7%89%88%EF%BC%89/04-%E9%81%93%E6%B0%8F%E7%90%86%E8%AE%BA%E5%9B%9B.html","title":"道氏理论四","lang":"zh-CN","frontmatter":{"date":"2024-01-17T00:00:00.000Z","category":["证券交易"],"tag":["道氏理论"],"order":4,"description":"道氏理论四 双顶和双底 “双顶”和“双底”在价格运动的预测中，价值不大。市场已经证明，其假象远比正确的时候多。 汉密尔顿不止一次声明，他认为从“双顶”或者“双底”得出的推论没有多大的重要性。有趣的是，不知道是谁首先让大众认为“双顶”和“双底”这样的现象是道氏理论的组成部分。 每当一个市场运动接近一个前期的高点或低点时，如果一个“双顶”或“双底”形成，我们肯定会读到从中得出的大量的无用于投机的评论。这样的评论常常是以如此的句子开头的，“根据道氏理论，如果工业平均价格指数形成‘双顶’”，等等。道氏理论的研究者都知道，单从一个平均价格指数是不能得出恰当的推论的。而且，两个平均价格指数同时形成“双顶”或“双底”是极少发生的。还有，即使同时发生了，也不过仅仅是一个巧合而已。如果把35年来的重大次级运动做个清点，就会发现只有极少的数量是以“双顶”或“双底”结束的。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/%E8%AF%81%E5%88%B8%E4%BA%A4%E6%98%93/%E9%81%93%E6%B0%8F%E7%90%86%E8%AE%BA%EF%BC%88%E5%9C%B0%E9%9C%87%E7%89%88%EF%BC%89/04-%E9%81%93%E6%B0%8F%E7%90%86%E8%AE%BA%E5%9B%9B.html"}],["meta",{"property":"og:site_name","content":"Journey of Growth"}],["meta",{"property":"og:title","content":"道氏理论四"}],["meta",{"property":"og:description","content":"道氏理论四 双顶和双底 “双顶”和“双底”在价格运动的预测中，价值不大。市场已经证明，其假象远比正确的时候多。 汉密尔顿不止一次声明，他认为从“双顶”或者“双底”得出的推论没有多大的重要性。有趣的是，不知道是谁首先让大众认为“双顶”和“双底”这样的现象是道氏理论的组成部分。 每当一个市场运动接近一个前期的高点或低点时，如果一个“双顶”或“双底”形成，我们肯定会读到从中得出的大量的无用于投机的评论。这样的评论常常是以如此的句子开头的，“根据道氏理论，如果工业平均价格指数形成‘双顶’”，等等。道氏理论的研究者都知道，单从一个平均价格指数是不能得出恰当的推论的。而且，两个平均价格指数同时形成“双顶”或“双底”是极少发生的。还有，即使同时发生了，也不过仅仅是一个巧合而已。如果把35年来的重大次级运动做个清点，就会发现只有极少的数量是以“双顶”或“双底”结束的。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2024-02-04T15:27:55.000Z"}],["meta",{"property":"article:author","content":"Mr.G"}],["meta",{"property":"article:tag","content":"道氏理论"}],["meta",{"property":"article:published_time","content":"2024-01-17T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2024-02-04T15:27:55.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"道氏理论四\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2024-01-17T00:00:00.000Z\\",\\"dateModified\\":\\"2024-02-04T15:27:55.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.G\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"双顶和双底","slug":"双顶和双底","link":"#双顶和双底","children":[]},{"level":2,"title":"个股","slug":"个股","link":"#个股","children":[]},{"level":2,"title":"投机交易","slug":"投机交易","link":"#投机交易","children":[]},{"level":2,"title":"股市哲学","slug":"股市哲学","link":"#股市哲学","children":[]},{"level":2,"title":"伟大的心灵","slug":"伟大的心灵","link":"#伟大的心灵","children":[]}],"git":{"createdTime":1707060475000,"updatedTime":1707060475000,"contributors":[{"name":"gm-hacker","email":"gm-hacker@qq.com","commits":1}]},"readingTime":{"minutes":35.13,"words":10539},"filePathRelative":"证券交易/道氏理论（地震版）/04-道氏理论四.md","localizedDate":"2024年1月17日","excerpt":"<h1> 道氏理论四</h1>\\n<h2> 双顶和双底</h2>\\n<p>“双顶”和“双底”在价格运动的预测中，价值不大。市场已经证明，其假象远比正确的时候多。</p>\\n<p>汉密尔顿不止一次声明，他认为从“双顶”或者“双底”得出的推论没有多大的重要性。有趣的是，不知道是谁首先让大众认为“双顶”和“双底”这样的现象是道氏理论的组成部分。</p>\\n<p>每当一个市场运动接近一个前期的高点或低点时，如果一个“双顶”或“双底”形成，我们肯定会读到从中得出的大量的无用于投机的评论。这样的评论常常是以如此的句子开头的，“根据道氏理论，如果工业平均价格指数形成‘双顶’”，等等。道氏理论的研究者都知道，单从一个平均价格指数是不能得出恰当的推论的。而且，两个平均价格指数同时形成“双顶”或“双底”是极少发生的。还有，即使同时发生了，也不过仅仅是一个巧合而已。如果把35年来的重大次级运动做个清点，就会发现只有极少的数量是以“双顶”或“双底”结束的。</p>","autoDesc":true}');export{e as data};
